/**
 * The Octonionic Router
 * 
 * Maps topological operations to the 7 imaginary basis vectors of the Fano Plane.
 * Executes queries by reducing the graph to a single dominant execution vector,
 * entirely bypassing associative control flow.
 */

import { OctonionBasis, OctonionState } from './fano-plane';
import { compileOctonionicAST, OctonionicAST, formatOctonionState } from './octonionic-compiler';
import { HologramNavigator } from './hologram-navigator';
import type { HologramPayload } from './data-hologram';

export type TopologicalOp = 
  | ':OBSERVE' // e1
  | ':SLIVER'  // e2
  | ':FOLD'    // e3
  | ':VENT'    // e4
  | ':FORK'    // e5
  | ':RACE'    // e6
  | ':DILATE'; // e7

/**
 * The Isomorphism mapping standard topological operations to the Fano Plane.
 */
export function mapOpToBasis(op: TopologicalOp): OctonionBasis {
  switch (op) {
    case ':OBSERVE': return 'e1';
    case ':SLIVER':  return 'e2';
    case ':FOLD':    return 'e3';
    case ':VENT':    return 'e4';
    case ':FORK':    return 'e5';
    case ':RACE':    return 'e6';
    case ':DILATE':  return 'e7';
  }
}

/**
 * Translates a query graph composed of operators into an Octonionic AST.
 */
export type OpGraph = TopologicalOp | [OpGraph, OpGraph];

/**
 * Builds the Octonionic AST.
 */
export function buildOctonionicAST(graph: OpGraph): OctonionicAST {
  if (typeof graph === 'string') {
    return mapOpToBasis(graph as TopologicalOp);
  }
  
  if (Array.isArray(graph) && graph.length === 2) {
    return [buildOctonionicAST(graph[0]), buildOctonionicAST(graph[1])];
  }

  throw new Error("Invalid OpGraph structure.");
}

/**
 * The Router executes a query against a Hologram payload using pure geometric evaluation.
 */
export class OctonionicRouter {
  private navigator: HologramNavigator;

  constructor(hologram: HologramPayload) {
    this.navigator = new HologramNavigator(hologram);
  }

  /**
   * Evaluates the non-associative AST and executes the dominant state vector.
   * Target is the context payload (e.g., column index and value).
   */
  public routeExecution(graph: OpGraph, targetCol: number, targetValue: string): HologramPayload {
    const ast = buildOctonionicAST(graph);
    const dominantState = compileOctonionicAST(ast);
    
    console.log(`[OctonionicRouter] Graph collapsed to dominant state: ${formatOctonionState(dominantState)}`);

    // The entire execution path is determined solely by the final geometry of the Fano Plane.
    switch (dominantState.basis) {
      case 'e6': {
        // e6 represents :RACE (Parallel intersection / Schubert slicing)
        // The sign (from the parenthesis grouping) dynamically sets the boundary operator.
        // Positive (+e6) = Forward Intersection (==)
        // Negative (-e6) = Inverse Intersection (!=)
        
        const operator = dominantState.sign === 1 ? '==' : '!=';
        console.log(`[OctonionicRouter] -> e6 mapped to :RACE. Sign [${dominantState.sign}] mapped to operator [${operator}]`);
        
        return this.navigator.intersectSchubert(() => false, {
          col: targetCol,
          op: operator,
          val: targetValue
        });
      }
      
      // Other bases would map to different physics engines (e.g. e1 to projectAffine).
      // For this integration proof, we focus on the e6 :RACE divergence.
      default:
        throw new Error(`Execution vector ${formatOctonionState(dominantState)} is not mapped to a runtime engine in this proof.`);
    }
  }
}
